/* FL Scratch-Off Statistician — local browser app over DATA (generated by build_site.py) */
"use strict";
const $=s=>document.querySelector(s);
const G=DATA.games, T=DATA.tiers, W=DATA.winners, M=DATA.meta;
const byNo=Object.fromEntries(G.map(g=>[g.game_no,g]));
const GAME_NAME=Object.fromEntries(G.map(g=>[g.game_no,g.game_name]));

/* ---------- formatting ---------- */
const money=v=>v==null?"—":(v>=1e6?"$"+(v/1e6).toLocaleString(undefined,{maximumFractionDigits:1})+"M":v>=1e3?"$"+(v/1e3).toLocaleString(undefined,{maximumFractionDigits:0})+"k":"$"+Math.round(v).toLocaleString());
const moneyFull=v=>v==null?"—":"$"+Math.round(v).toLocaleString();
const num=v=>v==null?"—":Math.round(v).toLocaleString();
const f2=v=>v==null?"—":(+v).toFixed(2);
const pct=v=>v==null?"—":(+v).toFixed(1)+"%";
const oddsF=v=>v==null?"—":"1 in "+(+v).toLocaleString(undefined,{maximumFractionDigits:2});
const esc=s=>String(s??"").replace(/[&<>"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[c]));
const anon=n=>/EXEMPT/.test(n||"");

/* ---------- charts registry ---------- */
let charts=[];
function newChart(el,cfg){const c=new Chart(el,cfg);charts.push(c);return c;}
function clearCharts(){charts.forEach(c=>c.destroy());charts=[];}
const gridC="rgba(128,128,128,.15)", tickC=getComputedStyle(document.body).color;
Chart.defaults.color=tickC; Chart.defaults.borderColor=gridC;
Chart.defaults.font.family=getComputedStyle(document.body).fontFamily;

/* ---------- router ---------- */
const mainEl=$("#main");
function go(tab,arg){location.hash=arg?tab+"/"+arg:tab;}
function route(){
  const [tab,arg]=(location.hash.replace(/^#/,"")||"overview").split("/");
  document.querySelectorAll("nav button").forEach(b=>b.classList.toggle("active",b.dataset.tab===tab));
  $("#nav-game").style.display=(tab==="game")?"":"none";
  clearCharts();
  ({overview,tickets,game,winners,retailers,maps,insights}[tab]||overview)(arg);
  window.scrollTo(0,0);
}
window.addEventListener("hashchange",route);
document.querySelectorAll("nav button").forEach(b=>b.onclick=()=>{if(b.dataset.tab!=="game")go(b.dataset.tab);});
$("#meta-line").textContent=`${M.n_games} games · ${M.n_winners} top-prize winners · data ${M.built}`;

/* ---------- sortable table helper ---------- */
function makeTable(cols,rows,opts={}){
  // cols: [{k,label,r?,fmt?,sortVal?}]
  let sortK=opts.sort||cols[0].k, dir=opts.dir||-1;
  const outer=document.createElement("div");
  outer.className="tblouter";
  const wrap=document.createElement("div");
  wrap.className="tablewrap";
  const fadeL=document.createElement("div"),fadeR=document.createElement("div");
  fadeL.className="fade fadeL";fadeR.className="fade fadeR";
  const hint=document.createElement("div");
  hint.className="scrollhint";hint.textContent="⟷ table continues — scroll sideways for more columns";
  outer.append(wrap,fadeL,fadeR,hint);
  function updateFades(){
    const more=wrap.scrollWidth-wrap.clientWidth>4;
    fadeR.classList.toggle("show",more&&wrap.scrollLeft<wrap.scrollWidth-wrap.clientWidth-4);
    fadeL.classList.toggle("show",more&&wrap.scrollLeft>4);
    hint.classList.toggle("show",more);
  }
  wrap.addEventListener("scroll",updateFades);
  new ResizeObserver(updateFades).observe(wrap);
  wrap.addEventListener("mouseover",e=>{
    const td=e.target.closest("td");
    if(td&&!td.title&&td.scrollWidth>td.clientWidth)td.title=td.textContent;
  });
  function val(row,c){return c.sortVal?c.sortVal(row):row[c.k];}
  function render(){
    const c0=cols.find(c=>c.k===sortK);
    const sorted=[...rows].sort((a,b)=>{
      const x=val(a,c0),y=val(b,c0);
      if(x==null&&y==null)return 0; if(x==null)return 1; if(y==null)return -1;
      return (typeof x==="string"?x.localeCompare(y):x-y)*dir;
    });
    let h='<table><thead><tr>'+cols.map(c=>`<th class="${c.r?"r":""}" data-k="${c.k}">${c.label}${c.k===sortK?` <span class="arr">${dir<0?"▼":"▲"}</span>`:""}</th>`).join("")+'</tr></thead><tbody>';
    for(const row of sorted){
      h+=`<tr${opts.rowClick?` class="click" data-id="${esc(opts.rowClick(row))}"`:""}>`+
        cols.map(c=>`<td class="${c.r?"r":""}">${c.fmt?c.fmt(row):esc(row[c.k]??"—")}</td>`).join("")+"</tr>";
    }
    wrap.innerHTML=h+"</tbody></table>";
    wrap.querySelectorAll("th").forEach(th=>th.onclick=()=>{
      const k=th.dataset.k;
      if(k===sortK)dir*=-1; else {sortK=k;dir=-1;}
      render();
    });
    if(opts.rowClick)wrap.querySelectorAll("tr.click").forEach(tr=>tr.onclick=()=>go("game",tr.dataset.id));
    requestAnimationFrame(updateFades);
  }
  render();
  return outer;
}

/* ---------- shared fragments ---------- */
function evCell(g){
  const v=g.value_per_dollar_now;
  if(v==null)return "—";
  const cls=v>=0.8?"good":v<0.7?"bad":"";
  return `<span class="${cls}">${f2(v)}</span>`;
}
function leftBar(g){
  const p=g.pct_value_remaining;
  if(p==null)return "—";
  const cls=p<10?"crit":p<25?"low":"";
  return `<div style="display:flex;align-items:center;gap:8px"><div class="bar ${cls}" style="width:80px"><i style="width:${Math.min(100,p)}%"></i></div><span class="mut">${pct(p)}</span></div>`;
}
function salePill(g){return g.on_sale?'<span class="pill on">on sale</span>':'<span class="pill off">ended</span>';}

const TICKET_COLS=[
  {k:"game_no",label:"#"},
  {k:"game_name",label:"Game"},
  {k:"ticket_price",label:"Price",r:1,fmt:g=>"$"+Math.round(g.ticket_price)},
  {k:"top_prize_value_num",label:"Top prize",r:1,fmt:g=>esc(g.top_prize_display||money(g.top_prize_value_num))},
  {k:"top_prizes_remaining",label:"TP left",r:1,fmt:g=>`${g.top_prizes_remaining??"—"}<span class="dim">/${g.top_prizes_total??"—"}</span>`},
  {k:"overall_odds_1_in",label:"Odds",r:1,fmt:g=>g.overall_odds_1_in?("1:"+g.overall_odds_1_in):"—"},
  {k:"value_per_dollar_now",label:"EV/$ now",r:1,fmt:evCell},
  {k:"value_per_dollar_original",label:"EV/$ design",r:1,fmt:g=>f2(g.value_per_dollar_original)},
  {k:"pct_value_remaining",label:"Value left",fmt:leftBar},
  {k:"on_sale",label:"Status",fmt:salePill},
];

/* ================= OVERVIEW ================= */
function overview(){
  const on=G.filter(g=>g.on_sale);
  const tpLeft=on.filter(g=>(g.top_prize_value_num||0)>=1e4).reduce((s,g)=>s+(g.top_prizes_remaining||0),0);
  const valLeft=on.reduce((s,g)=>s+(g.value_remaining||0),0);
  const big=G.filter(g=>g.on_sale&&g.top_prizes_remaining>0&&g.top_prize_value_num>=1e6);
  mainEl.innerHTML=`
  <div class="cards">
    <div class="card"><div class="lab">Games on sale</div><div class="val">${on.length}</div><div class="note">${G.length-on.length} ended</div></div>
    <div class="card"><div class="lab">Top prizes unclaimed</div><div class="val">${tpLeft}</div><div class="note">on-sale, $10k+ jackpots</div></div>
    <div class="card"><div class="lab">Prize money remaining</div><div class="val">${money(valLeft)}</div><div class="note">all tiers, on-sale</div></div>
    <div class="card"><div class="lab">$1M+ jackpots live</div><div class="val">${big.reduce((s,g)=>s+g.top_prizes_remaining,0)}</div><div class="note">across ${big.length} games</div></div>
    <div class="card"><div class="lab">Winners recorded</div><div class="val">${M.n_winners}</div><div class="note">all-time, these games</div></div>
  </div>
  <div class="panel"><h2>Best value right now <span class="hint">on-sale games ranked by expected payout per $1 of a remaining ticket</span></h2><div id="best"></div></div>
  <div class="grid2">
    <div class="panel"><h2>Biggest jackpots still out there</h2><div id="jack"></div></div>
    <div class="panel"><h2>Freshest games <span class="hint">most prize value left</span></h2><div id="fresh"></div></div>
  </div>`;
  $("#best").append(makeTable(TICKET_COLS,on.filter(g=>g.value_per_dollar_now!=null),{sort:"value_per_dollar_now",rowClick:g=>g.game_no}));
  const jrows=G.filter(g=>g.top_prizes_remaining>0&&g.top_prize_value_num>=2e6).map(g=>g);
  $("#jack").append(makeTable([
    {k:"game_name",label:"Game"},
    {k:"top_prize_value_num",label:"Top prize",r:1,fmt:g=>esc(g.top_prize_display||money(g.top_prize_value_num))},
    {k:"top_prizes_remaining",label:"Left",r:1},
    {k:"ticket_price",label:"Price",r:1,fmt:g=>"$"+Math.round(g.ticket_price)},
    {k:"on_sale",label:"",fmt:salePill},
  ],jrows,{sort:"top_prize_value_num",rowClick:g=>g.game_no}));
  $("#fresh").append(makeTable([
    {k:"game_name",label:"Game"},
    {k:"launch_date",label:"Launched"},
    {k:"pct_value_remaining",label:"Value left",fmt:leftBar},
    {k:"value_per_dollar_now",label:"EV/$",r:1,fmt:evCell},
  ],G.filter(g=>g.on_sale&&g.pct_value_remaining!=null),{sort:"pct_value_remaining",rowClick:g=>g.game_no}));
}

/* ================= ALL TICKETS ================= */
function tickets(){
  mainEl.innerHTML=`
  <div class="panel"><h2>All ${G.length} tickets</h2>
    <div class="controls">
      <input type="text" id="q" placeholder="Search game name or #…">
      <select id="price"><option value="">Any price</option>${[...new Set(G.map(g=>g.ticket_price))].sort((a,b)=>a-b).map(p=>`<option>${Math.round(p)}</option>`).join("")}</select>
      <div class="seg" id="sale"><button data-v="" class="active">All</button><button data-v="1">On sale</button><button data-v="0">Ended</button></div>
    </div>
    <div id="tbl"></div>
    <div class="sortnote">Click any column to sort · click a row for full game detail</div>
  </div>`;
  let q="",price="",sale="";
  function refresh(){
    const rows=G.filter(g=>
      (!q||g.game_name.toLowerCase().includes(q)||g.game_no.includes(q))&&
      (!price||Math.round(g.ticket_price)===+price)&&
      (sale===""||String(g.on_sale)===sale));
    $("#tbl").innerHTML="";
    $("#tbl").append(makeTable(TICKET_COLS,rows,{sort:"value_per_dollar_now",rowClick:g=>g.game_no}));
  }
  $("#q").oninput=e=>{q=e.target.value.toLowerCase();refresh();};
  $("#price").onchange=e=>{price=e.target.value;refresh();};
  document.querySelectorAll("#sale button").forEach(b=>b.onclick=()=>{
    sale=b.dataset.v;document.querySelectorAll("#sale button").forEach(x=>x.classList.toggle("active",x===b));refresh();});
  refresh();
}

/* ================= GAME DETAIL ================= */
function game(no){
  const g=byNo[no];
  if(!g){mainEl.innerHTML='<div class="panel">Unknown game.</div>';return;}
  const tiers=T[no]||[];
  const gw=W.filter(w=>w[0]===no);
  const flag=g.data_quality?`<div class="flagnote">⚠ ${esc(g.data_quality)}</div>`:"";
  mainEl.innerHTML=`
  <span class="back" onclick="history.back()">← back</span>
  <div class="gtitle">${esc(g.game_name)} <span class="dim">#${g.game_no}</span> ${salePill(g)}</div>
  <div class="gsub">$${Math.round(g.ticket_price)} ticket · top prize ${esc(g.top_prize_display||money(g.top_prize_value_num))} · overall odds 1:${g.overall_odds_1_in??"?"} · launched ${g.launch_date||"?"}${g.on_sale?"":" · ended "+g.end_date} · data ${esc(g.last_queried||"")}</div>
  ${flag}
  <div class="cards">
    <div class="card"><div class="lab">EV per $1 now</div><div class="val ${g.value_per_dollar_now>=0.8?"good":""}">${f2(g.value_per_dollar_now)}</div><div class="note">design ${f2(g.value_per_dollar_original)}</div></div>
    <div class="card"><div class="lab">Top prizes left</div><div class="val">${g.top_prizes_remaining??"—"} <span class="dim" style="font-size:15px">of ${g.top_prizes_total??"—"}</span></div></div>
    <div class="card"><div class="lab">Prize value left</div><div class="val">${money(g.value_remaining)}</div><div class="note">${pct(g.pct_value_remaining)} of ${money(g.value_original)}</div></div>
    <div class="card"><div class="lab">Est. tickets left</div><div class="val">${num(g.est_tickets_remaining)}</div><div class="note">of ~${num(g.est_tickets_printed)}</div></div>
  </div>
  <div class="grid2">
    <div class="panel"><h2>Prize tiers <span class="hint">official odds &amp; live counts</span></h2><div id="tierT"></div></div>
    <div class="panel"><h2>Tier depletion <span class="hint">% of each tier already claimed</span></h2><div class="chartbox"><canvas id="depC"></canvas></div></div>
  </div>
  <div class="panel"><h2>Top-prize winners on this game (${gw.length})</h2><div id="winT">${gw.length?"":'<span class="mut">None claimed yet.</span>'}</div></div>`;
  const trows=tiers.map(t=>({disp:t[0],val:t[1],odds:t[2],rem:t[3],orig:t[4],claimed:t[5]}));
  $("#tierT").append(makeTable([
    {k:"disp",label:"Prize",sortVal:r=>r.val},
    {k:"odds",label:"Odds",r:1,fmt:r=>oddsF(r.odds)},
    {k:"rem",label:"Remaining",r:1,fmt:r=>num(r.rem)},
    {k:"orig",label:"Original",r:1,fmt:r=>num(r.orig)},
    {k:"claimed",label:"% claimed",r:1,fmt:r=>r.orig?((100*r.claimed/r.orig).toFixed(1)+"%"):"—"},
  ],trows,{sort:"disp",dir:-1}));
  newChart($("#depC"),{type:"bar",data:{
    labels:trows.map(r=>r.disp),
    datasets:[{label:"% claimed",data:trows.map(r=>r.orig?100*r.claimed/r.orig:0),backgroundColor:"#E24B5B"},
              {label:"% remaining",data:trows.map(r=>r.orig?100*r.rem/r.orig:0),backgroundColor:"#2FB6A8"}]},
    options:{indexAxis:"y",responsive:true,maintainAspectRatio:false,
      scales:{x:{stacked:true,max:100,ticks:{callback:v=>v+"%"}},y:{stacked:true}},
      plugins:{legend:{position:"bottom"}}}});
  if(gw.length){
    $("#winT").append(makeTable([
      {k:"1",label:"Claimed",fmt:w=>w[1]||"—",sortVal:w=>w[1]||""},
      {k:"2",label:"Winner",fmt:w=>anon(w[2])?'<span class="dim">anonymous (90-day exemption)</span>':esc(w[2]),sortVal:w=>w[2]},
      {k:"3",label:"City",fmt:w=>esc(w[3]||"—"),sortVal:w=>w[3]||""},
      {k:"5",label:"Prize",r:1,fmt:w=>esc(w[5]),sortVal:w=>w[6]},
      {k:"8",label:"Payout",r:1,fmt:w=>esc(w[8]||"—"),sortVal:w=>w[8]||""},
      {k:"10",label:"Sold at",fmt:w=>esc(w[10]||"—"),sortVal:w=>w[10]||""},
    ],gw,{sort:"1"}));
  }
}

/* ================= WINNERS ================= */
function winners(){
  mainEl.innerHTML=`
  <div class="panel"><h2>All top-prize winners (${W.length})</h2>
    <div class="controls">
      <input type="text" id="wq" placeholder="Search name, city, retailer, game…">
      <select id="wmin"><option value="0">Any prize</option><option value="250000">$250k+</option><option value="1000000">$1M+</option><option value="5000000">$5M+</option></select>
      <label class="mut" style="font-size:13px"><input type="checkbox" id="wanon"> hide anonymous</label>
    </div>
    <div id="wtbl"></div>
  </div>`;
  let q="",min=0,hideA=false;
  function refresh(){
    const rows=W.filter(w=>
      (!q||[w[2],w[3],w[10],GAME_NAME[w[0]],w[0]].some(x=>(x||"").toLowerCase().includes(q)))&&
      ((w[6]||0)>=min)&&(!hideA||!anon(w[2])));
    $("#wtbl").innerHTML="";
    $("#wtbl").append(makeTable([
      {k:"1",label:"Claimed",fmt:w=>w[1]||"—",sortVal:w=>w[1]||""},
      {k:"0",label:"Game",fmt:w=>`${esc(GAME_NAME[w[0]]||w[0])} <span class="dim">#${w[0]}</span>`,sortVal:w=>GAME_NAME[w[0]]||""},
      {k:"2",label:"Winner",fmt:w=>anon(w[2])?'<span class="dim">anonymous</span>':esc(w[2]),sortVal:w=>w[2]},
      {k:"3",label:"City",fmt:w=>esc(w[3]||"—"),sortVal:w=>w[3]||""},
      {k:"6",label:"Prize",r:1,fmt:w=>esc(w[5]),sortVal:w=>w[6]},
      {k:"8",label:"Payout",r:1,fmt:w=>esc(w[8]||"—"),sortVal:w=>w[8]||""},
      {k:"10",label:"Sold at",fmt:w=>esc((w[10]||"—")+(w[11]?" — "+w[11]:"")),sortVal:w=>w[10]||""},
    ],rows,{sort:"1"}));
  }
  $("#wq").oninput=e=>{q=e.target.value.toLowerCase();refresh();};
  $("#wmin").onchange=e=>{min=+e.target.value;refresh();};
  $("#wanon").onchange=e=>{hideA=e.target.checked;refresh();};
  refresh();
}

/* ================= RETAILERS ================= */
function retailers(){
  const R=DATA.retail;
  if(!R){mainEl.innerHTML='<div class="panel">Retailer census not available in this build.</div>';return;}
  const topChain=R.chains[0];
  mainEl.innerHTML=`
  <div class="cards">
    <div class="card"><div class="lab">FL lottery retailers</div><div class="val">${num(R.total)}</div><div class="note">full statewide census</div></div>
    <div class="card"><div class="lab">Self-service vending</div><div class="val">${num(R.itvm)}</div><div class="note">${(100*R.itvm/R.total).toFixed(0)}% have a machine</div></div>
    <div class="card"><div class="lab">Publix locations</div><div class="val">${num(R.chains.find(c=>c.name==="Publix")?.stores)}</div><div class="note">most of any chain</div></div>
    <div class="card flam"><div class="lab">Base win rate</div><div class="val">${R.base_per1k}</div><div class="note">top-prize winners / 1,000 stores</div></div>
  </div>
  <div class="panel insight"><h2>Is any store "luckier"? <span class="hint">the honest answer</span></h2>
    <p class="mut" style="font-size:13.5px">No. Every top-prize winner is a random draw from tickets <em>sold</em>, so raw winner counts just track <b>sales volume</b>. To compare fairly we divide winners by each chain's actual store count (a real denominator from the ${num(R.total)}-store census). Even this is a rough proxy — it assumes every store sells the same volume — but it's far better than raw counts. Read <b>lift</b> as "winners per store vs. the statewide average": <b>1.0× = average</b>, above = more winners per location (i.e. more tickets sold there), below = fewer.</p></div>
  <div class="grid2">
    <div class="panel"><h2>By chain <span class="hint">winners per 1,000 stores vs. average</span></h2><div id="chainT"></div></div>
    <div class="panel"><h2>By store type</h2><div id="typeT"></div>
      <p class="mut" style="font-size:12.5px;margin-top:10px">Gas/convenience has the most winners overall only because Florida has ~${(R.types.find(t=>/Gas/.test(t.name))?.stores/1000).toFixed(1)}k of them. <b>Per store, supermarkets win ${(R.types.find(t=>/Grocery/.test(t.name))?.lift/R.types.find(t=>/Gas/.test(t.name))?.lift).toFixed(1)}× as often</b> — the "gas stations are luckier" idea is backwards.</p>
    </div>
  </div>`;
  const liftCell=r=>{const c=r.lift>=1.3?"good":r.lift<=0.7?"bad":"mut";return `<span class="lift ${c}">${r.lift.toFixed(2)}×</span>`;};
  $("#chainT").append(makeTable([
    {k:"name",label:"Chain"},
    {k:"stores",label:"FL stores",r:1,fmt:r=>num(r.stores)},
    {k:"winners",label:"Winners",r:1},
    {k:"per1k",label:"Per 1k stores",r:1,fmt:r=>r.per1k.toFixed(1)},
    {k:"lift",label:"Lift",r:1,fmt:liftCell},
  ],R.chains,{sort:"lift"}));
  $("#typeT").append(makeTable([
    {k:"name",label:"Type"},
    {k:"stores",label:"Stores",r:1,fmt:r=>num(r.stores)},
    {k:"winners",label:"Winners",r:1},
    {k:"per1k",label:"Per 1k",r:1,fmt:r=>r.per1k.toFixed(1)},
    {k:"lift",label:"Lift",r:1,fmt:liftCell},
  ],R.types,{sort:"lift"}));
}

/* ================= MAPS ================= */
function maps(){
  mainEl.innerHTML=`
  <div class="panel">
    <h2>Winner geography</h2>
    <div class="controls">
      <div class="seg" id="mmode"><button data-m="home" class="active">Winner homes</button><button data-m="ret">Where sold</button></div>
      <span class="mut" id="mcap"></span>
    </div>
    <div class="legend">
      <span class="mut">biggest prize:</span>
      <span><span class="sw" style="background:#E24B5B"></span>$25M</span>
      <span><span class="sw" style="background:#FF9E4A"></span>$5M+</span>
      <span><span class="sw" style="background:#FF6F91"></span>$2M</span>
      <span><span class="sw" style="background:#2FB6A8"></span>$1M</span>
      <span><span class="sw" style="background:#7d8f87"></span>&lt;$1M</span>
      <span class="mut">· circle size = winners in that city · hover for detail</span>
    </div>
    <div id="map-wrap"><div id="map"></div><div id="tip"></div></div>
  </div>`;
  const COL=[null,"#7d8f87","#2FB6A8","#FF6F91","#FF9E4A","#E24B5B"];
  const Wd=760,Hd=620;
  const svg=d3.select("#map").append("svg").attr("viewBox",`0 0 ${Wd} ${Hd}`).attr("width","100%");
  const proj=d3.geoMercator().fitExtent([[14,14],[Wd-14,Hd-14]],DATA.fl);
  const dark=matchMedia("(prefers-color-scheme: dark)").matches;
  svg.append("path").datum(DATA.fl).attr("d",d3.geoPath(proj))
     .attr("fill",dark?"#183029":"#ece2cf").attr("stroke",dark?"#2b433c":"#d7cbb3");
  const layer=svg.append("g");
  const tip=$("#tip"),wrap=$("#map-wrap");
  let mode="home";
  function draw(){
    const rows=(mode==="home"?DATA.map_home:DATA.map_ret).slice().sort((a,b)=>b[2]-a[2]);
    const tot=rows.reduce((s,r)=>s+r[2],0);
    $("#mcap").textContent=mode==="home"
      ?`${tot} winners across ${rows.length} home cities`
      :`${tot} winning tickets across ${rows.length} store cities`;
    layer.selectAll("circle").data(rows,r=>r[4]).join("circle")
      .attr("cx",r=>{const p=proj([r[0],r[1]]);return p?p[0]:-99;})
      .attr("cy",r=>{const p=proj([r[0],r[1]]);return p?p[1]:-99;})
      .attr("r",r=>3+Math.sqrt(r[2])*2).attr("fill",r=>COL[r[3]])
      .attr("fill-opacity",.72).attr("stroke",dark?"#111":"#fff").attr("stroke-width",.6)
      .on("mousemove",(ev,r)=>{
        const b=wrap.getBoundingClientRect();
        tip.innerHTML=`<b>${esc(r[4])}</b><br>${r[2]} ${mode==="home"?"winners":"tickets sold"}<br>biggest: ${money(r[5])}`;
        tip.style.opacity=1;
        let x=ev.clientX-b.left+14,y=ev.clientY-b.top+12;
        if(x>b.width-170)x-=190; tip.style.left=x+"px";tip.style.top=y+"px";})
      .on("mouseleave",()=>tip.style.opacity=0);
  }
  document.querySelectorAll("#mmode button").forEach(b=>b.onclick=()=>{
    mode=b.dataset.m;document.querySelectorAll("#mmode button").forEach(x=>x.classList.toggle("active",x===b));draw();});
  draw();
  // county table
  if(DATA.counties.length){
    const p=document.createElement("div");p.className="panel";
    p.innerHTML=`<h2>County analysis <span class="hint">winners vs population — index 1.0 = exactly proportional</span></h2><div id="cT"></div>`;
    mainEl.append(p);
    $("#cT").append(makeTable([
      {k:"county",label:"County"},
      {k:"pop",label:"Population",r:1,fmt:r=>num(r.pop)},
      {k:"winners",label:"Winners",r:1},
      {k:"per100k",label:"Per 100k",r:1},
      {k:"expected",label:"Expected",r:1},
      {k:"index",label:"Index",r:1,fmt:r=>r.index==null?"—":`<span class="${r.index>=1.5?"good":r.index<=0.6&&r.pop>200000?"bad":""}">${r.index.toFixed(2)}×</span>`},
    ],DATA.counties,{sort:"winners"}));
  }
}

/* ================= INSIGHTS ================= */
function insights(){
  mainEl.innerHTML=`
  <div class="panel insight"><h2>How to read this</h2>
    <p class="mut" style="font-size:13.5px">Every scratch-off is negative-EV — the best games return ~$0.80–0.92 per $1. <b>Which game</b> you pick matters far more than which price tier: payout is ~75% at every price point. The jackpot is marketing: it holds only 4–8% of a game's prize value. Cash-option payouts are ~63% of advertised face for big prizes.</p></div>
  <div class="grid2">
    <div class="panel"><h2>EV vs price <span class="hint">every on-sale game</span></h2><div class="chartbox"><canvas id="scat"></canvas></div></div>
    <div class="panel"><h2>Design payout by price tier</h2><div class="chartbox"><canvas id="payp"></canvas></div></div>
  </div>
  <div class="grid2">
    <div class="panel"><h2>Top-prize claims over time</h2><div class="chartbox"><canvas id="tline"></canvas></div></div>
    <div class="panel"><h2>Where the prize money sits <span class="hint">remaining value by tier size, all on-sale games</span></h2><div class="chartbox"><canvas id="split"></canvas></div></div>
  </div>`;
  const on=G.filter(g=>g.on_sale&&g.value_per_dollar_now!=null);
  newChart($("#scat"),{type:"scatter",data:{datasets:[{
      data:on.map(g=>({x:g.ticket_price,y:g.value_per_dollar_now,g})),
      pointRadius:5,pointHoverRadius:7,
      pointBackgroundColor:on.map(g=>g.value_per_dollar_now>=0.8?"#2FB6A8":g.value_per_dollar_now<0.7?"#E24B5B":"#FF9E4A")}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{
        label:c=>`${c.raw.g.game_name} (#${c.raw.g.game_no}): ${f2(c.raw.y)}/$ at $${Math.round(c.raw.x)}`}}},
      scales:{x:{title:{display:true,text:"ticket price ($)"},type:"linear"},
              y:{title:{display:true,text:"EV per $1 (now)"}}},
      onClick:(ev,els,chart)=>{if(els.length){go("game",chart.data.datasets[0].data[els[0].index].g.game_no);}}}});
  const prices=[...new Set(G.filter(g=>g.value_per_dollar_original!=null).map(g=>Math.round(g.ticket_price)))].sort((a,b)=>a-b);
  const avg=prices.map(p=>{const s=G.filter(g=>Math.round(g.ticket_price)===p&&g.value_per_dollar_original!=null);return s.reduce((t,g)=>t+g.value_per_dollar_original,0)/s.length;});
  newChart($("#payp"),{type:"bar",data:{labels:prices.map(p=>"$"+p),
      datasets:[{label:"avg design payout",data:avg.map(v=>+(100*v).toFixed(1)),backgroundColor:"#2FB6A8"}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{callbacks:{label:c=>c.raw+"% designed payout"}}},
      scales:{y:{min:50,max:85,ticks:{callback:v=>v+"%"}}}}});
  const tl=DATA.timeline.filter(t=>t[0]>="2022-10");
  newChart($("#tline"),{type:"bar",data:{labels:tl.map(t=>t[0]),
      datasets:[{label:"claims",data:tl.map(t=>t[1]),backgroundColor:"#FF6F91"}]},
    options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},
      scales:{x:{ticks:{maxRotation:60,autoSkip:true,maxTicksLimit:20}}}}});
  // remaining value split
  let buckets={"jackpot tier":0,"$10k–$1M":0,"$1k–$10k":0,"under $1k":0};
  for(const g of G.filter(g=>g.on_sale)){
    (T[g.game_no]||[]).forEach((t,i)=>{
      const v=t[1]*(t[3]||0);
      if(i===0)buckets["jackpot tier"]+=v;
      else if(t[1]>=1e4)buckets["$10k–$1M"]+=v;
      else if(t[1]>=1e3)buckets["$1k–$10k"]+=v;
      else buckets["under $1k"]+=v;});
  }
  newChart($("#split"),{type:"doughnut",data:{labels:Object.keys(buckets),
      datasets:[{data:Object.values(buckets).map(v=>Math.round(v/1e6)),
        backgroundColor:["#E24B5B","#FF9E4A","#FF6F91","#2FB6A8"],borderWidth:0}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:"bottom"},tooltip:{callbacks:{label:c=>` ${c.label}: $${c.raw}M remaining`}}}}});
}

route();
